+            // 1000 rows: id=1..1000, grp cycles 0..6 (just to have a second column)
+            for (int i = 0; i < 10; i++) {
+                assertUpdate("INSERT INTO " + table.getName() + " SELECT x, x %% 7 FROM UNNEST(sequence(%s, %s)) t(x)".formatted(i * 100 + 1, (i + 1) * 100), 100);
+            }
